	handle2, _ := strconv.Atoi(open2.String())

	if handle1 == handle2 {
		t.Fatal("Handles should be unique")
	}

	VMWrite(handle1, 0, "111")
	VMWrite(handle2, 0, "222")

	val1 := VMRead(handle1, 0)
